const discovery = $node['Call Onboarding Specialist: Auto-Discovery'].json.result || {};
const scope = $node['Validate Deal Data'].json.contract_scope || [];

const activationMilestones = [];
const ttv_targets = {};

if (scope.includes('paid_ads')) {
  activationMilestones.push({ channel: 'paid_ads', milestone: 'First campaign launched', day: 14, success_metric: 'First converted lead' });
  ttv_targets.paid_ads = 14;
}
if (scope.includes('content_seo')) {
  activationMilestones.push({ channel: 'content_seo', milestone: 'Content calendar published', day: 30, success_metric: 'First organic traffic' });
  ttv_targets.content_seo = 30;
}
if (scope.includes('email')) {
  activationMilestones.push({ channel: 'email', milestone: 'Email sequence deployed', day: 7, success_metric: 'First engagement' });
  ttv_targets.email = 7;
}
if (scope.includes('industrial') || scope.includes('complex')) {
  ttv_targets.complex = 45;
}

const successPlan = {
  goals: [],
  success_metrics: [],
  timeline: activationMilestones,
  ttv_targets,
  champion_map: { identified: false, count: 0, stakeholders: [] },
  status: 'draft'
};

return [{ json: { ...successPlan, discovery_report: discovery } }];

const activationHealth = 'Yellow'; // Initial onboarding health always Yellow (assumes basic setup)
const championMap = { count: 0, stakeholders: [] }; // To be updated post-kickoff

return [{ json: { client_id: $node['Validate Deal Data'].json.client_id, client_name: $node['Validate Deal Data'].json.client_name, activation_health: activationHealth, champion_count: championMap.count, onboarding_status: 'initiated', kickoff_scheduled: true } }];

